import asyncio
from fastapi import FastAPI, HTTPException

@app.post("/v1/chat")
async def chat(req: ChatRequest) -> ChatResponse:
    try:
        # Enforce a hard ceiling regardless of max_tokens requested
        result = await asyncio.wait_for(
            _run_inference(req),
            timeout=120.0,  # 2 minute hard ceiling per request
        )
        return result
    except asyncio.TimeoutError:
        raise HTTPException(status_code=504, detail="Inference timed out")

import hashlib, json
import redis.asyncio as aioredis

redis_client = aioredis.Redis(host="localhost", port=6379)
CACHE_TTL = 3600   # 1 hour; tune to how often model or prompts change

def _cache_key(req: ChatRequest) -> str:
    payload = json.dumps(
        {"model": req.model, "messages": req.messages, "temperature": req.temperature},
        sort_keys=True,
    )
    return "chat_cache:" + hashlib.sha256(payload.encode()).hexdigest()

@app.post("/v1/chat")
async def chat(req: ChatRequest) -> ChatResponse:
    # Skip cache for non-zero temperature (stochastic output)
    use_cache = req.temperature == 0.0
    key = _cache_key(req) if use_cache else None

    if key:
        cached = await redis_client.get(key)
        if cached:
            return ChatResponse.model_validate_json(cached)

    response = await _run_inference(req)

    if key:
        await redis_client.setex(key, CACHE_TTL, response.model_dump_json())

    return response
